  ('real-estate-moex-01256', 'real-estate', 'real-estate-moex-106-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '臺灣南部有許多鹽田，其價值評估以比較法估價為原則。若無買賣實例者，下列敘述何者正確？ 得以收益法估計之 得以成本法估計之 得以鹽田會員制度及曬鹽費用等因素推估之 得以附近土地價格為基礎，考慮其日照、通風、位置及形狀等差異，比較推估之', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:08+00:00", "source_pdf_sha1": "5605d540739a", "answer_pdf_sha1": "5609be6868db", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
